#include <bits/stdc++.h>
#define ull unsigned long long
using namespace std;
map<ull,int> m;
string f,c;
int n;
long long ans;
int main(){
    cin>>f;
    cin>>n;
    if(f.size()<8){
    	cout<<0;
    	return 0;
	}
    f=" "+f;
    ull h=0,w=1;
    for(int i=1;i<9;i++)
    	h+=f[i],w*=f[i];
	m[h+w]++;
	for(int i=2;i<f.size()-7;i++){
		h=h-f[i-1]+f[i+7],w=w/f[i-1]*f[i+7];
		m[h+w]++;
	}
	for(int i=1;i<=n;i++){
		h=0,w=1;
		cin>>c;
		for(int i=0;i<8;i++)
    		h+=c[i],w*=c[i];
    	ans+=m[h+w];
	}
	cout<<ans;
    return 0;
}
